(2115, 338, 'header', 'Fourth of July Fireworks'),
(2116, 338, '_header', 'field_664b0f798280d'),
(2117, 338, 'banner_content', '<p style=\"text-align: center;\">Every 4th of July, Americans honor the Declaration of Independence, celebrating freedom, patriotism, and unity.</p>\r\nAs families and friends gather for barbecues, parades, and festivities, fireworks illuminate the night sky, serving as a dazzling tribute to the nation\'s independence. At OC Fireworks, we understand the significance of this momentous day and are proud to be your premier destination for the best 4th of July fireworks for sale, elevating your celebration to new heights.'),
(2118, 338, '_banner_content', 'field_6655851f19ec8'),
(2119, 329, 'header', 'Elevate Your Wedding with OC Fireworks'),
(2120, 329, '_header', 'field_664b0f798280d'),
(2121, 329, 'banner_content', 'This exciting event deserves a spectacular display. Adding some fireworks to your wedding adds an unforgettable tale and leaves a lasting impression. It becomes a shared experience that everyone can talk about and cherish for years to come.'),
