(2526, 412, 'header', 'Spark Joy with 200-Gram Cakes!'),
(2527, 412, '_header', 'field_664b0f798280d'),
(2528, 412, 'banner_content', '<p style=\"text-align: center;\">Looking for a dazzling touch to add to your celebration? Explore our exciting selection of 200-gram cakes! These vibrant fireworks pack a punch, offering a beautiful display of color and effects at a perfect size for smaller gatherings or adding variety to a larger firework show.</p>'),
(2529, 412, '_banner_content', 'field_6655851f19ec8'),
(2530, 443, 'header', 'Borem ipsum dolor sit amet consectetur adipiscing elit'),
(2531, 443, '_header', 'field_664b0f798280d'),
(2532, 443, 'banner_content', '<p style=\"text-align: center;\">Korem ipsum dolor sit amet, consectetur adipiscing elit. Nunc vulputate libero et velit interdum, ac aliquet odio mattis. Class aptent taciti sociosqu ad litora torquent per conubia nostra, per inceptos himenaeos. Curabitur tempus urna at turpis.</p>'),
(2533, 443, '_banner_content', 'field_6655851f19ec8');
INSERT INTO `wp_postmeta` (`meta_id`, `post_id`, `meta_key`, `meta_value`) VALUES
(2534, 412, '_yoast_wpseo_title', '200 Gram Fireworks for Sale | Overstock Central Fireworks'),
(2535, 412, '_yoast_wpseo_metadesc', 'Shop online at OC Fireworks for 200 gram fireworks. Small size, big impact for your celebrations!'),
(2536, 441, 'header', 'Let\'s Get Whistlin\': Fun & Festive Fireworks for All'),
(2537, 441, '_header', 'field_664b0f798280d'),
(2538, 441, 'banner_content', '<p style=\"text-align: center;\">Get ready to add some serious \"whoosh\" to your next celebration with our epic Whistle Fireworks. Light them up, sit back, and enjoy the symphony of whistles and dazzling bursts that will leave your guests cheering for more!</p>'),
(2539, 441, '_banner_content', 'field_6655851f19ec8'),
(2540, 441, '_yoast_wpseo_title', 'Whistle Effect Fireworks | Overstock Central Fireworks'),
(2541, 441, '_yoast_wpseo_metadesc', 'OC Fireworks: Your source for whistle-effect fireworks. Explore our collection and ignite the sky with thrilling sounds!'),
(2542, 436, 'header', 'Get Ready to Spin Out!'),
(2543, 436, '_header', 'field_664b0f798280d'),
(2544, 436, 'banner_content', '<p style=\"text-align: center;\">Buckle up and get ready to spin with our awesome selection of spinner fireworks! These twirling beauties create a mesmerizing display of sparks and colorful flames, guaranteed to leave your guests starry-eyed (and maybe a little dizzy in the best way possible!).</p>'),
(2545, 436, '_banner_content', 'field_6655851f19ec8'),
(2546, 436, '_yoast_wpseo_title', 'Firework Spinners | Overstock Central Fireworks'),
(2547, 436, '_yoast_wpseo_metadesc', 'Firework spinners create dynamic motion, a stunning addition to any fireworks display. Get them from OC Fireworks today!'),
(2548, 435, 'header', 'Blast Off with Our Sky Rockets'),
(2549, 435, '_header', 'field_664b0f798280d'),
(2550, 435, 'banner_content', '<p style=\"text-align: center;\">Get ready to reach for the stars with our incredible selection of skyrockets! These sky-high flyers will add a touch of explosive fun to any celebration, leaving your guests in awe as they soar through the night sky with dazzling bursts of color.</p>'),
(2551, 435, '_banner_content', 'field_6655851f19ec8'),
(2552, 435, '_yoast_wpseo_title', 'Sky Rockets Fireworks | Overstock Central Fireworks'),
(2553, 435, '_yoast_wpseo_metadesc', 'OC Fireworks offers a variety of sky rocket fireworks. Create magical moments with our dazzling aerial rockets!'),
(2554, 434, 'header', ' Light Up the Fun, One Blast at a Time!'),
(2555, 434, '_header', 'field_664b0f798280d'),
(2556, 434, 'banner_content', '<p style=\"text-align: center;\">Our Single Shot Tubes are the perfect way to add pops of color and surprise to your celebration. With a variety of effects to choose from, you can create a custom light show that\'s easy to use and guaranteed to impress!</p>'),
(2557, 434, '_banner_content', 'field_6655851f19ec8'),
(2558, 434, '_yoast_wpseo_title', 'Single Shot Fireworks | Overstock Central Fireworks'),
(2559, 434, '_yoast_wpseo_metadesc', 'Light up the sky with our impressive, one-shot wonders with single-shot fireworks, available online from OC Fireworks!'),
(2560, 421, 'header', 'Let the Fun Repeat on You! '),
(2561, 421, '_header', 'field_664b0f798280d'),
(2562, 421, 'banner_content', '<p style=\"text-align: center;\">Get ready for a non-stop fireworks frenzy with our Repeater Effects Fireworks! These sparklers and firecrackers are all about rapid-fire fun, keeping the party pumping and the night sky illuminated.</p>'),
(2563, 421, '_banner_content', 'field_6655851f19ec8'),
(2564, 421, '_yoast_wpseo_title', 'Repeater Fireworks | Overstock Central Fireworks'),
(2565, 421, '_yoast_wpseo_metadesc', 'Create stunning, multi-shot displays with repeater fireworks for sale from OC Fireworks. Available in our online store!'),
(2566, 420, 'header', 'Take Your Celebration to New Heights!'),
(2567, 420, '_header', 'field_664b0f798280d'),
(2568, 420, 'banner_content', '<p style=\"text-align: center;\">Calling all thrill-seekers! Our Missile Page is packed with sky-rocketing missiles guaranteed to launch your celebration into another dimension. Get ready for epic bursts, dazzling trails, and a night to remember!</p>'),
(2569, 420, '_banner_content', 'field_6655851f19ec8'),
(2570, 420, '_yoast_wpseo_title', 'Missile Fireworks | Overstock Central Fireworks'),
(2571, 420, '_yoast_wpseo_metadesc', 'Buy missile fireworks online from OC Fireworks. Create unforgettable shows with our high-flying rockets!'),
(2572, 418, 'header', 'Light Up Your Diwali: It\'s a Festival of Fireworks!'),
(2573, 418, '_header', 'field_664b0f798280d'),
(2574, 418, 'banner_content', '<p style=\"text-align: center;\">Celebrate Diwali with the vibrant energy it deserves! Our Diwali Fireworks Page is bursting with dazzling sparklers, colorful rockets, and everything in between. Get ready to light up the night and make your Diwali unforgettable!</p>'),
(2575, 418, '_banner_content', 'field_6655851f19ec8'),
(2576, 418, '_yoast_wpseo_title', 'Diwali Fireworks | Overstock Central Fireworks'),
(2577, 418, '_yoast_wpseo_metadesc', 'Make a statement this Diwali with fireworks from OC Fireworks. Elevate your festivities with our vibrant displays!'),
(2578, 417, 'header', 'It\'s Time for Some Fizzy Fun!'),
(2579, 417, '_header', 'field_664b0f798280d'),
(2580, 417, 'banner_content', '<p style=\"text-align: center;\">Get ready to add a sizzling soundtrack to your celebration with our epic Crackle Effects Fireworks! Fill the night with pops, crackles, and fizzes that\'ll have your guests grinning from ear to ear.</p>'),
(2581, 417, '_banner_content', 'field_6655851f19ec8'),
(2582, 417, '_yoast_wpseo_title', 'Crackle Effect Fireworks | Overstock Central Fireworks'),
(2583, 417, '_yoast_wpseo_metadesc', 'OC Fireworks offers a wide selection of crackle-effect fireworks - featuring dazzling crackling displays!'),
(2584, 416, 'header', 'Slice Up the Night with Cake Fireworks!'),
(2585, 416, '_header', 'field_664b0f798280d'),
(2586, 416, 'banner_content', '<p style=\"text-align: center;\">Celebrate in style with our incredible selection of cake fireworks! Offering a delightful mix of shapes, sizes, and effects, these dazzling fireworks are guaranteed to add a touch of magic and excitement to any birthday party, anniversary, or special occasion.</p>'),
(2587, 416, '_banner_content', 'field_6655851f19ec8'),
(2588, 416, '_yoast_wpseo_title', 'Cake Fireworks | Overstock Central Fireworks'),
(2589, 416, '_yoast_wpseo_metadesc', 'Huge cake fireworks available online at OC Fireworks, offering create spectacular and long-lasting effects for any event. Shop now!'),
(2590, 415, 'header', 'Blast Off with Bottle Rockets!'),
(2591, 415, '_header', 'field_664b0f798280d'),
(2592, 415, 'banner_content', '<p style=\"text-align: center;\">Experience the classic thrill of bottle rockets! Our selection offers a variety of heights, bursts, and effects, perfect for adding a touch of nostalgic excitement and sky-high fun to any celebration. Buckle up and prepare for a soaring good time!</p>'),
(2593, 415, '_banner_content', 'field_6655851f19ec8'),
(2594, 415, '_yoast_wpseo_title', 'Bottle Rocket Fireworks | Overstock Central Fireworks'),
(2595, 415, '_yoast_wpseo_metadesc', 'Bottle Rocket Fireworks | Overstock Central Fireworks OC Fireworks offers a wide variety of bottle rocket fireworks. Adds excitement to any occasion!'),
(2596, 414, 'header', 'High-Caliber Fun with Artillery Shells'),
(2597, 414, '_header', 'field_664b0f798280d'),
(2598, 414, 'banner_content', '<p style=\"text-align: center;\">Transform your celebration into a breathtaking spectacle with our Artillery Shells. These high-performance fireworks deliver phenomenal aerial effects, creating a dazzling display that will leave your guests in awe.</p>'),
(2599, 414, '_banner_content', 'field_6655851f19ec8'),
(2600, 414, '_yoast_wpseo_title', 'Artillery Shells Fireworks | Overstock Central Fireworks'),
(2601, 414, '_yoast_wpseo_metadesc', 'Get ready for an explosive show with OC Fireworks\' artillery shell fireworks. Shop now for sky-high excitement!'),
(2602, 413, 'header', 'Reach for the Sky: Explore Our Aerial Fireworks!'),
(2603, 413, '_header', 'field_664b0f798280d'),
(2604, 413, 'banner_content', '<p style=\"text-align: center;\">Let the celebration take flight with our breathtaking selection of aerial fireworks! Experience our variety of options to paint the night sky with unforgettable bursts of color and light.</p>'),
(2605, 413, '_banner_content', 'field_6655851f19ec8'),
(2606, 413, '_yoast_wpseo_title', 'Aerial Fireworks | Overstock Central Fireworks'),
(2607, 413, '_yoast_wpseo_metadesc', 'Find the perfect aerial fireworks for your event at OC Fireworks. Shop our diverse selection here.'),
(2608, 411, 'header', '500g Cakes for Epic Celebrations'),
(2609, 411, '_header', 'field_664b0f798280d'),
(2610, 411, 'banner_content', '<p style=\"text-align: center;\">Ignite unforgettable memories with our showstopping 500-gram cakes! Offering a dazzling finale of color, sound, and effects, these powerful fireworks are the perfect way to elevate your celebration to the next level.</p>'),
(2611, 411, '_banner_content', 'field_6655851f19ec8'),
(2612, 411, '_yoast_wpseo_title', '500 Gram Fireworks for Sale | Overstock Central Fireworks'),
(2613, 411, '_yoast_wpseo_metadesc', 'Find top-quality 500 gram fireworks at OC Fireworks. Create spectacular shows with our top-rated products.'),
