(3832, 646, 'header', 'Send Your Wishes Aloft with Sky Lanterns'),
(3833, 646, '_header', 'field_664b0f798280d'),
(3834, 646, 'banner_content', '<p style=\"text-align: center;\">Send your wishes soaring with our sky lanterns, they\'re like mini hot air balloons carrying your wishes on the breeze! Watch them dance across the twilight sky for a truly unforgettable experience.</p>'),
(3835, 646, '_banner_content', 'field_6655851f19ec8'),
