(4583, 757, 'header', 'Become a Pro and Level Up Your Fireworks Show '),
(4584, 757, '_header', 'field_664b0f798280d'),
(4585, 757, 'banner_content', '<p style=\"text-align: center;\">Take your fireworks show from a backyard blast to an awe-inspiring spectacle with an electronic firing system. Ditch the unpredictable fuses and embrace precision control, elevating your displays to a pro-level masterpiece.</p>'),
(4586, 757, '_banner_content', 'field_6655851f19ec8'),
