(4625, 760, 'header', 'Explore the fuses that Make your Fireworks Display a Blast!'),
(4626, 760, '_header', 'field_664b0f798280d'),
(4627, 760, 'banner_content', '<p style=\"text-align: center;\">From slow burn to instant ignition, our Fireworks Fuse Page is the perfect match for your grand finale. Find the right fuse length and burn time to ensure a smooth, spectacular fireworks display, because a flawless show starts with the perfect spark.</p>'),
