(4866, 787, 'header', 'Light Up the Night, Watch Colors Take Flight'),
(4867, 787, '_header', 'field_664b0f798280d'),
(4868, 787, 'banner_content', '<p style=\"text-align: center;\">Our parachute fireworks take the party to new heights. These colorful bursts unfurl slowly, raining down a shower of sparkling fun for a grand finale that\'ll leave everyone saying \"Wow!\"</p>'),
(4869, 787, '_banner_content', 'field_6655851f19ec8'),
(4870, 788, 'header', 'Let OC Fireworks Planes Take Your Celebration Higher'),
(4871, 788, '_header', 'field_664b0f798280d'),
(4872, 788, 'banner_content', '<p style=\"text-align: center;\">Watch your party take flight with OC Fireworks\' Planes! These little buzz bombs zip, spin, and explode with a bang, leaving trails of dazzling color in their wake. Get ready for some sky-high fun that\'ll have everyone cheering!</p>'),
(4873, 788, '_banner_content', 'field_6655851f19ec8'),
(4874, 789, 'header', 'Experience Non stop Fun with Roman Candles'),
(4875, 789, '_header', 'field_664b0f798280d'),
(4876, 789, 'banner_content', '<p style=\"text-align: center;\">Watch in awe as bursts of color erupt one after another, filling the sky with dazzling displays. Choose from a fiery frenzy of 5 shots or a marathon of 668 – the party\'s in your hands!</p>'),
(4877, 789, '_banner_content', 'field_6655851f19ec8'),
(4878, 790, 'header', 'Celebrate Safely with OC Fireworks\' Safe & Sane Collection'),
(4879, 790, '_header', 'field_664b0f798280d'),
(4880, 790, 'banner_content', '<p style=\"text-align: center;\"> Our Safe and Sane fireworks are all fun and zero fuss. Think sparklers, sizzling snakes, and colorful fountains - perfect for backyard celebrations that won\'t wake the neighbors.</p>'),
(4881, 790, '_banner_content', 'field_6655851f19ec8'),
(4882, 791, 'header', 'Send Your Wishes Aloft with Sky Lanterns'),
(4883, 791, '_header', 'field_664b0f798280d'),
(4884, 791, 'banner_content', '<p style=\"text-align: center;\">Send your wishes soaring with our sky lanterns, they\'re like mini hot air balloons carrying your wishes on the breeze! Watch them dance across the twilight sky for a truly unforgettable experience.</p>'),
(4885, 791, '_banner_content', 'field_6655851f19ec8'),
(4886, 792, 'header', 'Whiz & Bang! Unleash the Snap Attack'),
(4887, 792, '_header', 'field_664b0f798280d'),
(4888, 792, 'banner_content', '<p style=\"text-align: center;\">Crackle the fun up a notch with OC Fireworks\' Snaps! Our collection of poppers, bangers, and whiz-bangs will have you popping with laughter and keeping the party snappin\' all night long. Get ready for some finger-snappin\' good times!</p>'),
(4889, 792, '_banner_content', 'field_6655851f19ec8'),
(4890, 793, 'header', 'Get the Sparkling Party Started with OC Fireworks'),
(4891, 793, '_header', 'field_664b0f798280d'),
(4892, 793, 'banner_content', '<p style=\"text-align: center;\">Want to add a touch of magic to your celebration? Light up the night with our dazzling sparklers! From backyard parties to wedding sparkler exits, we have the perfect sparklers to make your event shine</p>'),
(4893, 793, '_banner_content', 'field_6655851f19ec8'),
(4894, 794, 'header', 'Looking for Something Special? Check out these Fireworks '),
(4895, 794, '_header', 'field_664b0f798280d'),
(4896, 794, 'banner_content', '<p style=\"text-align: center;\">Tired of the same old sparklers and firecrackers? Looking to create a show-stopping finale for your next celebration? Explore our incredible selection of special fireworks and take your celebration to the next level!</p>'),
(4897, 794, '_banner_content', 'field_6655851f19ec8'),
(4898, 795, 'header', 'This Year\'s Hot List: New Fireworks for 2024'),
(4899, 795, '_header', 'field_664b0f798280d'),
(4900, 795, 'banner_content', '<p style=\"text-align: center;\">Looking to ignite your celebration? This year\'s hottest fireworks are here! From dazzling sparklers to show-stopping finale shells, discover the fireworks guaranteed to make your 2024 celebration unforgettable.</p>'),
(4901, 795, '_banner_content', 'field_6655851f19ec8'),
(4902, 796, 'header', 'Blast Off for Less: Budget-Friendly Shipping'),
(4903, 796, '_header', 'field_664b0f798280d'),
(4904, 796, 'banner_content', '<p style=\"text-align: center;\">Sending a gift or stocking up on supplies shouldn\'t break the bank! Our budget-friendly shipping options get your package where it needs to be without weighing down your wallet. Blast off for less and enjoy the savings!</p>'),
(4905, 796, '_banner_content', 'field_6655851f19ec8'),
(4906, 797, 'header', 'Fireworks Fun Delivered Free, No Sweat'),
(4907, 797, '_header', 'field_664b0f798280d'),
(4908, 797, 'banner_content', '<p style=\"text-align: center;\">Backyard fireworks extravaganza on the horizon? Your firework fun is just a click away! Get everything you need delivered straight to your door, absolutely free. No heavy lifting, no hidden fees, just pure fireworks excitement.</p>'),
(4909, 797, '_banner_content', 'field_6655851f19ec8'),
(4910, 798, 'header', 'Discover Our Counter Box Fireworks Deals!'),
(4911, 798, '_header', 'field_664b0f798280d'),
(4912, 798, 'banner_content', '<p style=\"text-align: center;\">Stock your shelves and satisfy your cravings with our Counter Boxes! Buy in bulk for epic savings on fan-favorite fireworks like smoke bombs and tanks. From single purchases to boxfuls of fun, we\'ve got everything you need to keep your fireworks counter crackling with excitement!</p>'),
(4913, 798, '_banner_content', 'field_6655851f19ec8'),
(4914, 799, 'header', 'Last Chance Bang! Don\'t Miss Out'),
(4915, 799, '_header', 'field_664b0f798280d'),
(4916, 799, 'banner_content', '<p style=\"text-align: center;\">This is your final call. Our epic sale ends soon. Grab these incredible deals before they\'re gone for good. Don\'t miss out, shop now and make a grand finale of your savings.</p>'),
(4917, 799, '_banner_content', 'field_6655851f19ec8'),
(4918, 800, 'header', 'Double the Fun, Double the Fireworks!'),
(4919, 800, '_header', 'field_664b0f798280d'),
(4920, 800, 'banner_content', '<p style=\"text-align: center;\">Double the Fun, Double the Fireworks! This Buy 1 Get 1 deal lets you stock up on your favorites or share the excitement with a friend. Don\'t miss out on this chance to make your next celebration truly explosive!</p>'),
(4921, 800, '_banner_content', 'field_6655851f19ec8'),
(4922, 801, 'header', 'Discover your perfect fireworks for any celebration'),
(4923, 801, '_header', 'field_664b0f798280d'),
(4924, 801, 'banner_content', '<p style=\"text-align: center;\">Our dazzling assortment of fireworks has everything you need to make your next event unforgettable. From grand finales to colorful bursts, find the perfect display for any occasion.</p>'),
(4925, 801, '_banner_content', 'field_6655851f19ec8'),
(4926, 802, 'header', 'Fireworks Fun for Under Five Bucks'),
(4927, 802, '_header', 'field_664b0f798280d'),
(4928, 802, 'banner_content', '<p style=\"text-align: center;\">Celebrate with a bang without breaking the bank! Our Fireworks Fun for Under Five Bucks selection lets you add dazzling pops and colorful bursts to your celebration – all for a budget-friendly price.</p>'),
(4929, 802, '_banner_content', 'field_6655851f19ec8'),
(4930, 803, 'header', 'Gear Up with the Right Tubes & Racks for Epic Fireworks'),
(4931, 803, '_header', 'field_664b0f798280d'),
(4932, 803, 'banner_content', '<p style=\"text-align: center;\">Take your fireworks game to the next level! Our Tubes &amp; Racks Page has everything you need to launch an unforgettable finale. Find the perfect tubes for your mortars and the sturdiest racks to send them soaring.</p>'),
(4933, 803, '_banner_content', 'field_6655851f19ec8'),
(4934, 804, 'header', 'Become a Pro and Level Up Your Fireworks Show '),
(4935, 804, '_header', 'field_664b0f798280d'),
(4936, 804, 'banner_content', '<p style=\"text-align: center;\">Take your fireworks show from a backyard blast to an awe-inspiring spectacle with an electronic firing system. Ditch the unpredictable fuses and embrace precision control, elevating your displays to a pro-level masterpiece.</p>'),
(4937, 804, '_banner_content', 'field_6655851f19ec8'),
(4938, 805, 'header', 'Explore the fuses that Make your Fireworks Display a Blast!'),
(4939, 805, '_header', 'field_664b0f798280d'),
(4940, 805, 'banner_content', '<p style=\"text-align: center;\">From slow burn to instant ignition, our Fireworks Fuse Page is the perfect match for your grand finale. Find the right fuse length and burn time to ensure a smooth, spectacular fireworks display, because a flawless show starts with the perfect spark.</p>'),
(4941, 805, '_banner_content', 'field_6655851f19ec8');
