(230, 230, 'fireworks-for-events', '<p style=\"text-align: center\">Every 4th of July, Americans honor the Declaration of Independence, celebrating freedom, patriotism, and unity.\r\n\r\nAs families and friends gather for barbecues, parades, and festivities, fireworks illuminate the night sky, serving as a dazzling tribute to the nation\'s independence. At OC Fireworks, we understand the significance of this momentous day and are proud to be your premier destination for the best 4th of July fireworks for sale, elevating your celebration to new heights.</p>', 0, 11),
(231, 231, 'fireworks-for-events', '', 0, 11),
(232, 232, 'fireworks-for-events', '', 0, 11),
(233, 233, 'product_cat', '<p style=\"text-align: center\">Buying wholesale fireworks online is the savvy choice for event planners and pyro enthusiasts! At OC Fireworks, we offer a huge selection of top-quality products at discounted prices. Whether it\'s a big bash or an intimate gathering, get more bang for your buck with wholesale fireworks online!</p>\r\n<p style=\"text-align: center\">With the convenience of online shopping and the assurance of bulk discounts, our team makes it easy to stock up on fireworks for any occasion, ensuring a memorable and exhilarating experience for all.</p>', 0, 11),
